#include <cuda_runtime.h>
#include <cstdlib>
#include <iostream>
#include <string>
#include <cstring>
#include <cstdio>
#include <cmath>
#include <chrono>

#ifdef TIMING
#include <sys/time.h>
#endif

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

__global__ void BFS_1(const Node* g_graph_nodes,
                      const int* g_graph_edges,
                      char* g_graph_mask,
                      char* g_updating_graph_mask,
                      char* g_graph_visited,
                      int* g_cost,
                      const int no_of_nodes);

__global__ void BFS_2(char* g_graph_mask,
                      char* g_updating_graph_mask,
                      char* g_graph_visited,
                      char* g_over,
                      const int no_of_nodes);

int work_group_size = 512;
int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef PROFILING
class timer {
public:
    timer(const char* = 0) : running(false), elapsed(0.0) {}
    void reset() { running = false; elapsed = 0.0; }
    void start() { running = true; t0 = std::chrono::high_resolution_clock::now(); }
    void stop() {
        if (running) {
            auto t1 = std::chrono::high_resolution_clock::now();
            elapsed += std::chrono::duration<double>(t1 - t0).count();
            running = false;
        }
    }
    double getTimeInSeconds() { return elapsed; }
private:
    bool running;
    double elapsed;
    std::chrono::high_resolution_clock::time_point t0;
};
#endif

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const timeval* t1, const timeval* t0, timeval* td) {
    td->tv_sec = t1->tv_sec - t0->tv_sec;
    td->tv_usec = t1->tv_usec - t0->tv_usec;
    if (td->tv_usec < 0) {
        td->tv_sec--;
        td->tv_usec += 1000000;
    }
}
#endif

static inline void cudaCheck(cudaError_t err, const char* where) {
    if (err != cudaSuccess) {
        std::string msg = std::string(where) + " -> " + cudaGetErrorString(err);
        throw msg;
    }
}

void _clCmdParams(int argc, char* argv[]) {
    for (int i = 0; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'g':
                if (++i < argc) {
                    sscanf(argv[i], "%u", &work_group_size);
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw std::string("bad command line");
                }
                break;
            case 'd':
                if (++i < argc) {
                    sscanf(argv[i], "%u", &device_id_inuse);
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw std::string("bad command line");
                }
                break;
            case 'p':
                if (++i < argc) {
                    sscanf(argv[i], "%u", &platform_id_inuse);
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw std::string("bad command line");
                }
                break;
            default:
                ;
        }
    }
}

template <typename datatype>
void compare_results(const datatype* cpu_results, const datatype* gpu_results, const int size) {
    char passed = true;
    for (int i = 0; i < size; i++) {
        if (cpu_results[i] != gpu_results[i]) {
            passed = false;
        }
    }
    if (passed) {
        std::cout << "--cambine:passed:-)" << std::endl;
    } else {
        std::cout << "--cambine: failed:-(" << std::endl;
    }
}

void run_bfs_cpu(int no_of_nodes, Node* h_graph_nodes, int edge_list_size,
                 int* h_graph_edges, char* h_graph_mask, char* h_updating_graph_mask,
                 char* h_graph_visited, int* h_cost_ref) {
    (void)edge_list_size;
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting);
                     i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
    (void)k;
}

void run_bfs_gpu(int no_of_nodes, Node* h_graph_nodes, int edge_list_size,
                 int* h_graph_edges, char* h_graph_mask, char* h_updating_graph_mask,
                 char* h_graph_visited, int* h_cost) {
    char h_over = false;
    Node* d_graph_nodes = nullptr;
    int* d_graph_edges = nullptr;
    char *d_graph_mask = nullptr, *d_updating_graph_mask = nullptr, *d_graph_visited = nullptr, *d_over = nullptr;
    int* d_cost = nullptr;

    try {
#ifdef TIMING
        gettimeofday(&tv_total_start, NULL);
        gettimeofday(&tv_mem_alloc_start, NULL);
        tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
        init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        cudaCheck(cudaSetDevice(device_id_inuse), "cudaSetDevice");

        cudaCheck(cudaMalloc((void**)&d_graph_nodes, no_of_nodes * sizeof(Node)), "cudaMalloc d_graph_nodes");
        cudaCheck(cudaMalloc((void**)&d_graph_edges, edge_list_size * sizeof(int)), "cudaMalloc d_graph_edges");
        cudaCheck(cudaMalloc((void**)&d_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_mask");
        cudaCheck(cudaMalloc((void**)&d_updating_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_updating_graph_mask");
        cudaCheck(cudaMalloc((void**)&d_graph_visited, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_visited");
        cudaCheck(cudaMalloc((void**)&d_cost, no_of_nodes * sizeof(int)), "cudaMalloc d_cost");
        cudaCheck(cudaMalloc((void**)&d_over, sizeof(char)), "cudaMalloc d_over");

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        cudaCheck(cudaMemcpy(d_graph_nodes, h_graph_nodes, no_of_nodes * sizeof(Node), cudaMemcpyHostToDevice), "memcpy nodes");
        cudaCheck(cudaMemcpy(d_graph_edges, h_graph_edges, edge_list_size * sizeof(int), cudaMemcpyHostToDevice), "memcpy edges");
        cudaCheck(cudaMemcpy(d_graph_mask, h_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "memcpy mask");
        cudaCheck(cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "memcpy updating mask");
        cudaCheck(cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "memcpy visited");
        cudaCheck(cudaMemcpy(d_cost, h_cost, no_of_nodes * sizeof(int), cudaMemcpyHostToDevice), "memcpy cost");

#ifdef PROFILING
        timer kernel_timer;
        double ktime = 0.0;
        kernel_timer.reset();
        kernel_timer.start();
#endif

        int block = work_group_size;
        if (block <= 0) block = 1;
        if (block > 1024) block = 1024;
        int grid = (no_of_nodes + block - 1) / block;

        do {
            h_over = false;
            cudaCheck(cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice), "memcpy over H2D");

            BFS_1<<<grid, block>>>(d_graph_nodes, d_graph_edges, d_graph_mask,
                                   d_updating_graph_mask, d_graph_visited, d_cost, no_of_nodes);
            cudaCheck(cudaGetLastError(), "launch BFS_1");

            BFS_2<<<grid, block>>>(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);
            cudaCheck(cudaGetLastError(), "launch BFS_2");

            cudaCheck(cudaMemcpy(&h_over, d_over, sizeof(char), cudaMemcpyDeviceToHost), "memcpy over D2H");
        } while (h_over);

        cudaCheck(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

#ifdef PROFILING
        kernel_timer.stop();
        ktime = kernel_timer.getTimeInSeconds();
        std::cout << "kernel time(s):" << ktime << std::endl;
#endif

        cudaCheck(cudaMemcpy(h_cost, d_cost, no_of_nodes * sizeof(int), cudaMemcpyDeviceToHost), "memcpy cost D2H");

#ifdef TIMING
        gettimeofday(&tv_close_start, NULL);
#endif

        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);
    } catch (std::string msg) {
        if (d_graph_nodes) cudaFree(d_graph_nodes);
        if (d_graph_edges) cudaFree(d_graph_edges);
        if (d_graph_mask) cudaFree(d_graph_mask);
        if (d_updating_graph_mask) cudaFree(d_updating_graph_mask);
        if (d_graph_visited) cudaFree(d_graph_visited);
        if (d_cost) cudaFree(d_cost);
        if (d_over) cudaFree(d_over);
        std::string e_str = "in run_transpose_gpu -> ";
        e_str += msg;
        throw e_str;
    }

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

void Usage(int argc, char** argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char* argv[]) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    FILE* fp = nullptr;
    Node* h_graph_nodes = nullptr;
    char *h_graph_mask = nullptr, *h_updating_graph_mask = nullptr, *h_graph_visited = nullptr;

    try {
        char* input_f;
        if (argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        _clCmdParams(argc, argv);
        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;
        fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        work_group_size = num_of_threads_per_block;
        (void)num_of_blocks;

        h_graph_nodes = (Node*)malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char*)malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char*)malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char*)malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;
        for (int i = 0; i < no_of_nodes; i++) {
            fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;

        fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        int* h_graph_edges = (int*)malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            fscanf(fp, "%d", &id);
            fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp) fclose(fp);

        int* h_cost = (int*)malloc(sizeof(int) * no_of_nodes);
        int* h_cost_ref = (int*)malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;
        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        if (fp) fclose(fp);
    }

    return 0;
}
